    fun getSops(): List<SopEntity> {
        return rawData.mapIndexed { index, pair ->
            val num = index + 11 // Start from SOP-GEN-011 (since SOP-GEN-001 to SOP-GEN-010 exist in SopPrepopulationData.generalSops)
            val codeStr = String.format("SOP-GEN-%03d", num)
            
            // Map category, department, role based on the index intervals
            val (dept, cat, role) = when {
                index < 26 -> Triple("SOPs", "Warehouse & Inventory Control", "Warehouse Executive")
                index < 52 -> Triple("Quality Control", "Quality Control Instruments", "Analyst")
                index < 78 -> Triple("Microlab", "Microbiology Laboratory Systems", "Analyst")
                index < 104 -> Triple("Quality Assurance", "Quality Assurance & Audits", "QA Officer")
                index < 130 -> Triple("Production", "Production Operations & Packaging", "Operator")
                index < 156 -> Triple("SOPs", "Engineering & Facilities Management", "Engineer")
                index < 182 -> Triple("SOPs", "Water Systems & Utilities", "Engineer")
                index < 208 -> Triple("SOPs", "Safety, Health & Environment", "Safety Officer")
                index < 234 -> Triple("Validation", "Validation & Qualification", "QA Officer")
                else -> Triple("SOPs", "Regulatory Compliance & Documentation", "QA Officer")
            }

            // Generate clean standard step-by-step procedure text
            val steps = pair.second.split(", ", "; ").toMutableList()
            if (steps.size < 4) {
                steps.add("Ensure all tools and relevant documentation are ready and verified prior to commencing the procedure.")
                steps.add("Perform the primary tasks sequentially with strict double-checks and contemporaneous data recordings.")
                steps.add("Verify the final results meet current Good Manufacturing Practice (cGMP) limit specifications.")
                steps.add("Clean the operational area, document the physical results inside the logbooks, and submit to QA supervisor for review.")
            }
            val formattedProcedure = steps.joinToString(";") { it.trim().replaceFirstChar { char -> char.uppercase() } }

            SopEntity(
                code = codeStr,
                title = pair.first,
                department = dept,
                section = cat,
                objective = pair.second,
                scope = "This standard operating procedure is applicable to all standard processes, operations, validations, or documentation executed inside the $cat division of the pharmaceutical site.",
                responsibility = "All $role personnel are responsible for strict compliance. Supervisors are responsible for review and QA is responsible for oversight.",
                procedure = formattedProcedure,
                safetyPrecautions = "Always wear appropriate personal protective equipment (PPE).;Follow standard Lock-Out-Tag-Out (LOTO) and ESD protections where applicable.",
                frequency = "Biennially (Every 2 years) or after major changes.",
                effectiveDate = "2026-06-28",
                roleRequired = role
            )
        }
    }
